import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Helper function to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('thunder') || conditionLower.includes('storm')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌤️'; // default
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* City and condition header */}
            {/* City and condition header */}
            <Row justify="between" align="center">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <span aria-label={props.condition}>{getWeatherEmoji(props.condition)}</span>
            </Row>

            {/* Current temperature - large and prominent */}
            {/* Current temperature and condition - large and prominent */}
            <Stack gap="var(--ggui-spacing-3)" align="center">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)" align="center">
                {props.temperature}°{props.unit}
              </Text>
              <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)" align="center">
                {props.condition}
              </Text>
            </Stack>

            {/* Weather condition text */}


            {/* Divider */}
            <Divider margin="var(--ggui-spacing-4)" />

            {/* Humidity and Wind Speed Grid */}
            {/* Humidity and Wind Speed Grid */}
            <Row gap="var(--ggui-spacing-4)">
              {/* Humidity card */}
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)" style={{ flex: 1 }}>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" aria-label="Humidity icon" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text size="2xl" weight="semibold" color="var(--ggui-color-primary-700)">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Box>

              {/* Wind Speed card */}
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)" style={{ flex: 1 }}>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" aria-label="Wind speed icon" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text size="2xl" weight="semibold" color="var(--ggui-color-primary-700)">
                    {props.windSpeed} {props.unit === 'F' ? 'mph' : 'km/h'}
                  </Text>
                </Stack>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-3)" wrap={true}>
              {props.forecast && props.forecast.length > 0 ? (
                props.forecast.slice(0, 5).map((day, index) => (
                  <Box key={index} padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)" style={{ flex: '0 1 calc(20% - var(--ggui-spacing-2))' }}>
                    <Stack gap="var(--ggui-spacing-2)" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        {day.day || `Day ${index + 1}`}
                      </Text>
                      <span aria-label={day.icon ? `${day.icon} weather` : `${props.condition} weather`} style={{ fontSize: 'var(--ggui-font-size-3xl)' }}>
                        {day.icon || getWeatherEmoji('clear')}
                      </span>
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)">
                          {day.high !== undefined ? `${day.high}°${props.unit}` : '--'}
                        </Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          {day.low !== undefined ? `${day.low}°${props.unit}` : '--'}
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                ))
              ) : (
                <Text color="var(--ggui-color-onSurfaceVariant)">No forecast data available</Text>
              )}
            </Row>
       </Stack>
         </Card>
       </Stack>
     </Container>
   );
}

