import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for tab and quantity selection
  const [activeTab, setActiveTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);

  // Derived state
  const stock = props.product.stock ?? 0;
  const isInStock = stock > 0;
  const isLowStock = stock > 0 && stock <= 5;
  const stockBadgeVariant = isLowStock ? 'warning' : 'success';
  const stockBadgeText = isLowStock ? 'Low Stock' : 'In Stock';

  // Handle quantity change
  const handleQuantityChange = useCallback((newQuantity: number) => {
    const clamped = Math.max(1, Math.min(newQuantity, stock));
    setQuantity(clamped);
  }, [stock]);

  // Handle Add to Cart
  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Tab definitions
  const tabs = [
    {
      key: 'description',
      label: 'Description',
      content: <Text>{props.product.description || 'No description available'}</Text>,
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: renderSpecifications(props.product.specifications),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: renderReviews(props.product.reviews),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Top section: Image, Title, Price, Rating, Stock */}
        <Row gap="var(--ggui-spacing-6)" align="start">
          {/* Product image placeholder */}
          <Box
            width="300px"
            height="300px"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
            display="flex"
            alignItems="center"
            justifyContent="center"
          >
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Icon name="image" size={48} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{props.product.name}</Text>
            </Stack>
          </Box>
          {/* Product details */}
          <Stack gap="var(--ggui-spacing-4)" flex={1}>
            <Heading level={1}>{props.product.name}</Heading>
            {/* Price and Currency */}
            <Text variant="bodyLarge" weight="semibold">
              {props.product.currency || '$'}{(props.product.price ?? 0).toFixed(2)}
            </Text>
            {/* Rating stars */}
            <Row gap="var(--ggui-spacing-2)" align="center">
              {renderRatingStars(props.product.rating ?? 0)}
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                ({props.product.reviewCount ?? 0} reviews)
              </Text>
            </Row>
            {/* Stock status badge */}
            <Badge variant={stockBadgeVariant}>{stockBadgeText}</Badge>
          </Stack>
        </Row>

        {/* Middle section: Tabs */}
        <Card padding="var(--ggui-spacing-4)" shadow="md">
          <Tabs
            items={tabs}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            size="md"
          />
        </Card>

        {/* Bottom section: Quantity Selector and Add to Cart */}
        <Card padding="var(--ggui-spacing-4)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
            {/* Quantity selector */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Text variant="label">Quantity:</Text>
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleQuantityChange(quantity - 1)}
                disabled={quantity <= 1}
              >
                −
              </Button>
              <Box width="50px" display="flex" alignItems="center" justifyContent="center">
                <Text align="center">{quantity}</Text>
              </Box>
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleQuantityChange(quantity + 1)}
                disabled={quantity >= stock}
              >
                +
              </Button>
            </Stack>
            <Spacer size="flex" />
            {/* Add to Cart button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={!isInStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

// Helper function to render rating stars
function renderRatingStars(rating: number) {
  const stars = [];
  const filledStars = Math.round(rating);
  for (let i = 0; i < 5; i++) {
    stars.push(
      <Icon
        key={i}
        name="star"
        size={20}
        color={i < filledStars ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}
      />
    );
  }
  return stars;
}

// Helper function to render specifications table
function renderSpecifications(specs: unknown[] | undefined) {
  if (!specs || !Array.isArray(specs) || specs.length === 0) {
    return <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>;
  }
  // Cast specs as array of {key, value} objects
  const specArray = specs as Array<{ key?: string; value?: string }>;
  return (
    <Table
      columns={[
        { key: 'key', header: 'Property', align: 'left' },
        { key: 'value', header: 'Value', align: 'left' },
      ]}
      data={specArray}
      compact
    />
  );
}

// Helper function to render reviews list
function renderReviews(reviews: unknown[] | undefined) {
  if (!reviews || !Array.isArray(reviews) || reviews.length === 0) {
    return <Text color="var(--ggui-color-onSurfaceVariant)">No reviews available</Text>;
  }
  // Cast reviews as array of review objects
  const reviewArray = reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>;
  return (
    <Stack gap="var(--ggui-spacing-4)">
      {reviewArray.map((review, idx) => (
        <Card key={idx} padding="var(--ggui-spacing-3)" shadow="sm">
          <Stack gap="var(--ggui-spacing-2)">
            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
              <Text variant="label">{review.author || 'Anonymous'}</Text>
              <Row gap="var(--ggui-spacing-1)">
                {Array.from({ length: 5 }, (_, i) => (
                  <Icon
                    key={i}
                    name="star"
                    size={16}
