  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // State
  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages);
  const [inputText, setInputText] = useState('');
  const [typingUser, setTypingUser] = useState<{ sender?: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messageList, scrollToBottom]);

  // Handle new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessageList((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active && typing.latest.sender) {
        setTypingUser({ sender: typing.latest.sender });
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      sendMessage({
        text: inputText,
        timestamp: new Date().toISOString(),
      });
      setInputText('');
    }
  }, [inputText, sendMessage]);

  // Handle Enter key
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Format timestamp
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ text?: string; timestamp?: string }>;
    }> = [];

    messageList.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({
          sender: msg.sender,
          messages: [{ text: msg.text, timestamp: msg.timestamp }],
        });
      }
    });

    return groups;
  }, [messageList]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
<Card shadow="md" radius="lg" padding="var(--ggui-spacing-4)" border={true}>
<Stack gap="var(--ggui-spacing-4)" direction="vertical">
