                <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
              </Stack>
              {typingUser && typingUser.sender && (
                <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typingUser.sender} is typing</Text>
                  <Spinner size={16} color="var(--ggui-color-primary-600)" />
