              maxHeight: 'calc(100vh - 400px)',
              minHeight: '400px',
            }}
          >
            <Stack gap="var(--ggui-spacing-3)" direction="vertical">
              {groupedMessages.length === 0 ? (
                <Box
                  padding="var(--ggui-spacing-6)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ textAlign: 'center' }}
                >
                  <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start a conversation!</Text>
                </Box>
              ) : (
                groupedMessages.map((group, groupIdx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  return (
                    <Stack
                      key={groupIdx}
                      gap="var(--ggui-spacing-2)"
                      direction="vertical"
                      align={isCurrentUser ? 'end' : 'start'}
                    >
                      {!isCurrentUser && group.sender && (
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                          {group.sender}
                        </Text>
                      )}
                        <Box
                          key={`${groupIdx}-${msgIdx}`}
                          padding="var(--ggui-spacing-3)"
                          padding="var(--ggui-spacing-3)"
                          background={
                            isCurrentUser
                              ? 'var(--ggui-color-primary-600)'
                              : 'var(--ggui-color-surfaceVariant)'
                          }
                          borderRadius="var(--ggui-shape-radius-lg)"
                          style={{
                            maxWidth: '60%',
                            wordWrap: 'break-word',
                          }}
                        >
                          <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                            <Text
                              color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurfaceVariant)'}
                              variant="body"
                            >
                              {msg.text}
                            </Text>
                            <Text
                              color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                              variant="caption"
                            >
                              {formatTime(msg.timestamp)}
                            </Text>
                          </Stack>
                        </Box>
                      ))}
                    </Stack>
                  );
                })
              )}
              <div ref={messagesEndRef} />
            </Stack>
          </Box>
          <Divider orientation="horizontal" margin="0" color="var(--ggui-color-outlineVariant)" />

          {/* Input Area */}
          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)">
            <Row gap="var(--ggui-spacing-2)" align="end">
              <TextArea
                label="Message"
                placeholder="Type your message here..."
                value={inputText}
