type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displaying merged stock data and last update time
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<string>('');
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const highlightTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Merge incoming priceUpdate stream events into displayed stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setDisplayStocks((prev) => {
        return prev.map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price !== undefined ? update.price : stock.price,
              change: update.change !== undefined ? update.change : stock.change,
              changePercent: update.changePercent !== undefined ? update.changePercent : stock.changePercent,
            };
          }
          return stock;
        });
      });
      // Trigger flash animation on symbol
      if (update.symbol) {
        setHighlightedSymbols((prev) => new Set(prev).add(update.symbol));
        if (highlightTimeoutRef.current) {
          clearTimeout(highlightTimeoutRef.current);
        }
        highlightTimeoutRef.current = setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
        }, 500);
      }
      // Update timestamp to current time
      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, [priceUpdate.latest]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (highlightTimeoutRef.current) {
        clearTimeout(highlightTimeoutRef.current);
      }
    };
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and last updated timestamp */}
        <Row justify="between" align="center">
