            Last Updated: {lastUpdated || 'Loading...'}
          </Text>
        </Row>

        {/* Responsive grid of stock cards */}
<CardGrid columns={3} gap={24}>
          {displayStocks.map((stock) => {
            const isHighlighted = highlightedSymbols.has(stock.symbol || '');
            const isPositive = (stock.change ?? 0) >= 0;
            const textColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
            const borderColor = isPositive ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
                radius="md"
                style={{
                  borderColor: borderColor,
                  transition: 'background-color 300ms ease-in-out',
                  backgroundColor: isHighlighted
                    ? 'var(--ggui-color-primary-50)'
                    : 'var(--ggui-color-surface)',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Ticker symbol - large and bold */}
                  <Text
                    variant="body"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                  >
                    {stock.symbol || 'N/A'}
                  </Text>

                  {/* Company name */}
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {stock.name || 'Unknown'}
                  </Text>

                  {/* Price formatted with 2 decimals */}
                  <Text
                    variant="bodyLarge"
                    weight="semibold"
                    color="var(--ggui-color-onSurface)"
                  >
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>

                  {/* Change with color coding and arrow */}
                  <Row gap="var(--ggui-spacing-1)" align="center">
                    <Text variant="body" color={textColor} weight="medium">
                      {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                    </Text>
                    <Text variant="body" color={textColor} weight="medium">
                      ({isPositive ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%)
                    </Text>
                    <Icon
                      name={isPositive ? 'arrow-up' : 'arrow-down'}
                      size={16}
                      color={textColor}
                    />
                  </Row>
                </Stack>
              </Card>
            );
          })}
