type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };


export default function Component(props: Props) {
  // State management for the wizard
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });
  const [emailError, setEmailError] = useState('');

  // Wire hook for completion action
  const complete = useAction<ActionCompletePayload>('onComplete');

  // Email validation helper
  const validateEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  // Validation checks for current step
  const isStep1Valid = useCallback(() => {
    const nameValid = formData.name.trim().length > 0;
    const emailValid = formData.email.trim().length > 0 && validateEmail(formData.email);
    const avatarValid = formData.avatar.trim().length > 0;
    if (formData.email.trim().length > 0 && !validateEmail(formData.email)) {
      setEmailError('Please enter a valid email address');
      return false;
    }
    setEmailError('');
    return nameValid && emailValid && avatarValid;
  }, [formData.name, formData.email, formData.avatar, validateEmail]);

  const isStep2Valid = useCallback(() => {
    return formData.role.trim().length > 0;
  }, [formData.role]);

  const canProceed = useCallback(() => {
    if (step === 1) return isStep1Valid();
    if (step === 2) return isStep2Valid();
    return true;
  }, [step, isStep1Valid, isStep2Valid]);

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (!canProceed()) return;
    if (step < 3) setStep(step + 1);
  }, [step, canProceed]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep(step - 1);
  }, [step]);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid() || !isStep2Valid()) return;
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  }, [formData, isStep1Valid, isStep2Valid, complete]);

  // Handle email validation on change
  const handleEmailChange = useCallback((value: string) => {
    setFormData((prev) => ({ ...prev, email: value }));
    if (value.trim().length > 0 && !validateEmail(value)) {
      setEmailError('Please enter a valid email address');
    } else {
      setEmailError('');
    }
  }, [validateEmail]);
  return (
