              {[1, 2, 3].map((stepNum) => (
                <React.Fragment key={stepNum}>
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={step === stepNum ? 'var(--ggui-color-primary-600)' : step > stepNum ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-outlineVariant)'}
                    borderRadius="var(--ggui-shape-radius-full)"
                    style={{ minWidth: '40px', minHeight: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                  >
                    <Text color="white" align="center" variant="label">
                      {step > stepNum ? '✓' : stepNum}
                    </Text>
                  </Box>
                  {stepNum < 3 && (
                    <Box
                      style={{
                        height: '2px',
                        flex: 1,
                        background: step > stepNum ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-outlineVariant)',
                        transition: 'background-color 0.3s ease',
                      }}
                    />
                  )}
                </React.Fragment>
              ))}
            </Row>
            <Text align="center" variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of 3
            </Text>
          </Stack>
        </Box>

        {/* Step 1: Profile Setup */}
        {step === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Profile Setup</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
