              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" is="label">
                  Choose Avatar *
                </Text>
                <Row gap="var(--ggui-spacing-3)" align="center">
                  {props.avatarOptions.map((emojiAvatar) => (
                    <Box
                      key={emojiAvatar}
                      as={Clickable}
                      onClick={() => setFormData((prev) => ({ ...prev, avatar: emojiAvatar }))}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={formData.avatar === emojiAvatar ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      role="radio"
