                      }}
                    >
                      {emojiAvatar}
                    </Box>
                  ))}
                </Row>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {step === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Preferences</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Customize your experience.
              </Text>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => setFormData((prev) => ({ ...prev, role: value }))}
                options={props.roleOptions.map((role) => ({ value: role, label: role }))}
                placeholder="Select your role"
                required
                error={formData.role.trim().length === 0 && formData.role.length > 0 ? 'Role is required' : ''}
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Enable Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => setFormData((prev) => ({ ...prev, emailNotifications: checked }))}
              />

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Theme Preference
                </Text>
                <Row gap="var(--ggui-spacing-3)" align="center">
                  {['light', 'dark'].map((themeOption) => (
                    <Box
                      key={themeOption}
                      as={Clickable}
                      onClick={() => setFormData((prev) => ({ ...prev, theme: themeOption }))}
                      padding="var(--ggui-spacing-3)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={formData.theme === themeOption ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      role="radio"
                      tabIndex={0}
                      aria-label={themeOption === 'light' ? 'Light theme' : 'Dark theme'}
                      aria-checked={formData.theme === themeOption}
                      style={{
                        cursor: 'pointer',
                        border: formData.theme === themeOption ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)',
                        transition: 'all 0.2s ease',
                        textAlign: 'center',
                        minWidth: '100px',
                      }}
                    >
                      <Text variant="label" color="var(--ggui-color-onSurface)">
                        {themeOption.charAt(0).toUpperCase() + themeOption.slice(1)}
                      </Text>
                    </Box>
                  ))}
                </Row>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {step === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Setup</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please review your information before completing setup.
              </Text>
              <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" radius="md">
                <Stack gap="var(--ggui-spacing-3)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Full Name</Text>
                    <Text variant="body">{formData.name}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                    <Text variant="body">{formData.email}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                    <Text variant="body" size="xl">{formData.avatar}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                    <Text variant="body">{formData.role}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                    <Text variant="body">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                    <Text variant="body">{formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row justify="between" gap="var(--ggui-spacing-3)">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
          >
            Go Back
          </Button>
          {step < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canProceed()}
            >
              Next
            </Button>
          )}
          {step === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
              disabled={!isStep1Valid() || !isStep2Valid()}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
